module RefModule(
    input [7:0] in,
    input [2:0] shift_amount,
    input shift_direction,
    output [7:0] out
);reg [7:0] unused_shifted;

    always @(*) begin
        case(shift_direction)
            1'b0: unused_shifted = in >> shift_amount;
            1'b1: unused_shifted = in << shift_amount;
        endcase
    end

    assign out = unused_shifted;

endmodule
